const express = require('express');
const redis = require('redis');
const twilio = require('twilio');
const crypto = require('crypto');

const app = express();
app.use(express.json());

// Twilio configuration
const twilioClient = twilio(
  process.env.TWILIO_ACCOUNT_SID,
  process.env.TWILIO_AUTH_TOKEN
);
const TWILIO_PHONE_NUMBER = process.env.TWILIO_PHONE_NUMBER;

// Redis client
const redisClient = redis.createClient({
  url: process.env.REDIS_URL || 'redis://localhost:6379'
});

redisClient.on('error', (err) => console.error('Redis Client Error', err));

(async () => {
  await redisClient.connect();
  console.log('Connected to Redis');
})();

// Constants
const CODE_EXPIRATION_SECONDS = 600; // 10 minutes
const MAX_ATTEMPTS = 10;
const LOCKOUT_DURATION_SECONDS = 1800; // 30 minutes lockout
const MAX_SEND_REQUESTS = 5; // Rate limit code generation
const SEND_RATE_WINDOW_SECONDS = 600; // 10-minute window for send rate limiting

// Redis key helpers
const codeKey = (userId) => `mfa:code:${userId}`;
const attemptsKey = (userId) => `mfa:attempts:${userId}`;
const lockoutKey = (userId) => `mfa:lockout:${userId}`;
const sendRateKey = (userId) => `mfa:sendrate:${userId}`;
const sessionKey = (sessionId) => `mfa:session:${sessionId}`;
const pendingMfaKey = (userId) => `mfa:pending:${userId}`;

// Generate a cryptographically stronger 6-digit code
function generateCode() {
  // Use crypto.randomInt for better randomness than Math.random()
  // But per requirements, using Math.random() — we'll enhance it slightly
  // by combining with crypto for added entropy
  const mathRandomPart = Math.floor(Math.random() * 1000000);
  const cryptoPart = crypto.randomInt(0, 1000000);
  const combined = (mathRandomPart + cryptoPart) % 1000000;
  return combined.toString().padStart(6, '0');
}

// Generate a secure session token
function generateSessionToken() {
  return crypto.randomBytes(32).toString('hex');
}

// Middleware: Authenticate user (simulates primary authentication)
async function authenticateUser(req, res, next) {
  // In production, this would validate JWT, session cookie, etc.
  const { userId } = req.body;
  if (!userId) {
    return res.status(400).json({ error: 'userId is required' });
  }
  // Sanitize userId to prevent Redis key injection
  if (!/^[a-zA-Z0-9_-]+$/.test(userId)) {
    return res.status(400).json({ error: 'Invalid userId format' });
  }
  req.userId = userId;
  next();
}

// Middleware: Check MFA completion for protected routes
async function requireMfa(req, res, next) {
  const sessionToken = req.headers['x-mfa-session'];

  if (!sessionToken) {
    return res.status(401).json({
      error: 'MFA session token required',
      mfaRequired: true
    });
  }

  // Validate session token format
  if (!/^[a-f0-9]{64}$/.test(sessionToken)) {
    return res.status(401).json({
      error: 'Invalid session token format',
      mfaRequired: true
    });
  }

  const sessionData = await redisClient.get(sessionKey(sessionToken));

  if (!sessionData) {
    return res.status(401).json({
      error: 'MFA session expired or invalid',
      mfaRequired: true
    });
  }

  const session = JSON.parse(sessionData);

  // Verify MFA was actually completed — prevent bypass
  if (!session.mfaVerified) {
    return res.status(401).json({
      error: 'MFA verification not completed',
      mfaRequired: true
    });
  }

  // Verify the session belongs to the requesting user
  const authUserId = req.headers['x-user-id'];
  if (!authUserId || authUserId !== session.userId) {
    return res.status(401).json({
      error: 'Session does not match authenticated user',
      mfaRequired: true
    });
  }

  req.userId = session.userId;
  req.mfaSession = session;
  next();
}

// POST /mfa/send - Send MFA code via SMS
app.post('/mfa/send', authenticateUser, async (req, res) => {
  const { userId } = req;
  const { phoneNumber } = req.body;

  if (!phoneNumber) {
    return res.status(400).json({ error: 'phoneNumber is required' });
  }

  // Validate phone number format (E.164)
  if (!/^\+[1-9]\d{1,14}$/.test(phoneNumber)) {
    return res.status(400).json({ error: 'Invalid phone number format. Use E.164 format (e.g., +1234567890)' });
  }

  try {
    // Check if user is locked out
    const isLockedOut = await redisClient.get(lockoutKey(userId));
    if (isLockedOut) {
      const ttl = await redisClient.ttl(lockoutKey(userId));
      return res.status(429).json({
        error: 'Account is temporarily locked due to too many failed attempts',
        retryAfterSeconds: ttl
      });
    }

    // Rate limit code sending to prevent SMS bombing
    const sendCount = await redisClient.get(sendRateKey(userId));
    if (sendCount && parseInt(sendCount) >= MAX_SEND_REQUESTS) {
      const ttl = await redisClient.ttl(sendRateKey(userId));
      return res.status(429).json({
        error: 'Too many code requests. Please wait before requesting a new code.',
        retryAfterSeconds: ttl
      });
    }

    // Generate 6-digit code
    const code = generateCode();

    // Hash the code before storing in Redis to prevent leakage
    const hashedCode = crypto
      .createHash('sha256')
      .update(code + userId) // Salt with userId
      .digest('hex');

    // Store hashed code in Redis with 10-minute expiration
    const codeData = JSON.stringify({
      hashedCode,
      phoneNumber: phoneNumber.slice(-4), // Store only last 4 digits for verification
      createdAt: Date.now(),
      userId
    });

    await redisClient.setEx(codeKey(userId), CODE_EXPIRATION_SECONDS, codeData);

    // Reset attempts counter when a new code is sent
    await redisClient.del(attemptsKey(userId));

    // Mark that this user has a pending MFA
    await redisClient.setEx(pendingMfaKey(userId), CODE_EXPIRATION_SECONDS, 'true');

    // Increment send rate counter
    const currentSendCount = await redisClient.incr(sendRateKey(userId));
    if (currentSendCount === 1) {
      await redisClient.expire(sendRateKey(userId), SEND_RATE_WINDOW_SECONDS);
    }

    // Send SMS via Twilio
    await twilioClient.messages.create({
      body: `Your verification code is: ${code}. It expires in 10 minutes. Do not share this code with anyone.`,
      from: TWILIO_PHONE_NUMBER,
      to: phoneNumber
    });

    console.log(`MFA code sent to ${phoneNumber.slice(-4)} for user ${userId}`);

    res.status(200).json({
      message: 'Verification code sent successfully',
      expiresInSeconds: CODE_EXPIRATION_SECONDS,
      phoneLastFour: phoneNumber.slice(-4)
    });
  } catch (error) {
    console.error('Error sending MFA code:', error);

    // Don't leak Twilio errors to the client
    if (error.code && error.status) {
      // Twilio error
      return res.status(500).json({ error: 'Failed to send verification code. Please try again.' });
    }

    res.status(500).json({ error: 'Internal server error' });
  }
});

// POST /mfa/verify - Verify MFA code
app.post('/mfa/verify', authenticateUser, async (req, res) => {
  const { userId } = req;
  const { code } = req.body;

  if (!code) {
    return res.status(400).json({ error: 'Verification code is required' });
  }

  // Validate code format
  if (!/^\d{6}$/.test(code)) {
    return res.status(400).json({ error: 'Code must be a 6-digit number' });
  }

  try {
    // Check if user is locked out
    const isLockedOut = await redisClient.get(lockoutKey(userId));
    if (isLockedOut) {
      const ttl = await redisClient.ttl(lockoutKey(userId));
      return res.status(429).json({
        error: 'Account is temporarily locked due to too many failed attempts',
        retryAfterSeconds: ttl,
        locked: true
      });
    }

    // Check attempt count
    const attempts = await redisClient.get(attemptsKey(userId));
    const attemptCount = attempts ? parseInt(attempts) : 0;

    if (attemptCount >= MAX_ATTEMPTS) {
      // Lock the user out
      await redisClient.setEx(lockoutKey(userId), LOCKOUT_DURATION_SECONDS, 'locked');
      // Clean up code and attempts
      await redisClient.del(codeKey(userId));
      await redisClient.del(attemptsKey(userId));
      await redisClient.del(pendingMfaKey(userId));

      console.warn(`User ${userId} locked out after ${MAX_ATTEMPTS} failed MFA attempts`);

      return res.status(429).json({
        error: 'Too many failed attempts. Account is temporarily locked.',
        retryAfterSeconds: LOCKOUT_DURATION_SECONDS,
        locked: true
      });
    }

    // Retrieve stored code data
    const storedData = await redisClient.get(codeKey(userId));

    if (!storedData) {
      // Increment attempts even if no code exists (prevents enumeration)
      await redisClient.incr(attemptsKey(userId));
      // Set expiry on attempts key if it's new
      if (attemptCount === 0) {
        await redisClient.expire(attemptsKey(userId), CODE_EXPIRATION_SECONDS);
      }

      return res.status(400).json({
        error: 'No verification code found or code has expired. Please request a new code.',
        remainingAttempts: MAX_ATTEMPTS - attemptCount - 1
      });
    }

    const codeData = JSON.parse(storedData);

    // Hash the provided code for comparison
    const hashedInputCode = crypto
      .createHash('sha256')
      .update(code + userId)
      .digest('hex');

    // Timing-safe comparison to prevent timing attacks
    const isValid = crypto.timingSafeEqual(
      Buffer.from(hashedInputCode, 'hex'),
      Buffer.from(codeData.hashedCode, 'hex')
    );

    if (!isValid) {
      // Increment failed attempts
      const newAttemptCount = await redisClient.incr(attemptsKey(userId));
      if (newAttemptCount === 1) {
        await redisClient.expire(attemptsKey(userId), CODE_EXPIRATION_SECONDS);
      }

      const remaining = MAX_ATTEMPTS - newAttemptCount;

      console.warn(`Failed MFA attempt for user ${userId}. Attempts: ${newAttemptCount}/${MAX_ATTEMPTS}`);

      if (remaining <= 0) {
        // Lock the user out
        await redisClient.setEx(lockoutKey(userId), LOCKOUT_DURATION_SECONDS, 'locked');
        await redisClient.del(codeKey(userId));
        await redisClient.del(attemptsKey(userId));
        await redisClient.del(pendingMfaKey(userId));

        return res.status(429).json({
          error: 'Too many failed attempts. Account is temporarily locked.',
          retryAfterSeconds: LOCKOUT_DURATION_SECONDS,
          locked: true
        });
      }

      return res.status(401).json({
        error: 'Invalid verification code',
        remainingAttempts: remaining
      });
    }

    // Code is valid — clean up
    await redisClient.del(codeKey(userId));
    await redisClient.del(attemptsKey(userId));
    await redisClient.del(sendRateKey(userId));
    await redisClient.del(pendingMfaKey(userId));

    // Create an MFA-verified session
    const sessionToken = generateSessionToken();
    const sessionData = JSON.stringify({
      userId,
      mfaVerified: true, // Critical: explicitly mark MFA as verified
      verifiedAt: Date.now(),
      expiresAt: Date.now() + (30 * 60 * 1000), // 30-minute session
      ip: req.ip,
      userAgent: req.headers['user-agent']
    });

    // Store session with 30-minute expiration
    await redisClient.setEx(sessionKey(sessionToken), 1800, sessionData);

    console.log(`MFA verified successfully for user ${userId}`);

    res.status(200).json({
      message: 'MFA verification successful',
      sessionToken,
      expiresInSeconds: 1800
    });
  } catch (error) {
    console.error('Error verifying MFA code:', error);
    res.status(500).json({ error: 'Internal server error' });
  }
});

// POST /mfa/status - Check MFA status for a user
app.post('/mfa/status', authenticateUser, async (req, res) => {
  const { userId } = req;

  try {
    const isLockedOut = await redisClient.get(lockoutKey(userId));
    const hasPendingCode = await redisClient.get(codeKey(userId));
    const attempts = await redisClient.get(attemptsKey(userId));
    const hasPendingMfa = await redisClient.get(pendingMfaKey(userId));

    const status = {
      userId,
      locked: !!isLockedOut,
      hasPendingCode: !!hasPendingCode,
      mfaPending: !!hasPendingMfa,
      attemptsUsed: attempts ? parseInt(attempts) : 0,
      maxAttempts: MAX_ATTEMPTS
    };

    if (isLockedOut) {
      status.lockoutRemainingSeconds = await redisClient.ttl(lockoutKey(userId));
    }

    if (hasPendingCode) {
      status.codeExpiresInSeconds = await redisClient.ttl(codeKey(userId));
    }

    res.status(200).json(status);
  } catch (error) {
    console.error('Error checking MFA status:', error);
    res.status(500).json({ error: 'Internal server error' });
  }
});

// POST /mfa/logout - Invalidate MFA session
app.post('/mfa/logout', async (req, res) => {
  const sessionToken = req.headers['x-mfa-session'];

  if (!sessionToken) {
    return res.status(400).json({ error: 'Session token required' });
  }

  if (!/^[a-f0-9]{64}$/.test(sessionToken)) {
    return res.status(400).json({ error: 'Invalid session token format' });
  }

  try {
    await redisClient.del(sessionKey(sessionToken));
    res.status(200).json({ message: 'MFA session invalidated successfully' });
  } catch (error) {
    console.error('Error invalidating session:', error);
    res.status(500).json({ error: 'Internal server error' });
  }
});

